/**
 * Course-home builder (Module S). Owner decision (2026-07-06): the student-site
 * VIEWS are the self-contained files themselves — a chapter is served as its
 * `.md.html` (slides as `.slides.html`, practice as its own `.md.html`, print
 * as `.paged.html`). Those files are generated by the caller (the worker);
 * this module builds only the **course home**, a navigation hub that links to
 * them (hub-and-spoke) — redesigned 2026-07-09 as the course's table of
 * contents: a hero (title + instructor/course number/department + intro), a
 * numbered module list per chapter (study guide always; slides/practice links
 * only when that chapter has authored one), and a placeholder section for the
 * not-yet-finalized "current term" space.
 *
 * Layout:
 *   index.html   — hero + module list + current-term placeholder
 *   build-info.json, .nojekyll
 *
 * The chapter/slides/practice/paged pages themselves (self-contained files)
 * are added to the file set by the caller after generation. Copy-as-source,
 * themes, and math all come from the self-contained files' own runtime — and
 * the home itself is `themedDocument`, so it carries the orz runtime too.
 * Home chrome (siteStyle) is layered on the chosen orz theme (dark-elegant /
 * light-academic, theme-css.ts) rather than inventing a third visual identity
 * — the home is the front door to documents styled in that same system.
 *
 * `buildSite` (single-page callers) is untouched.
 */

import { md } from "orz-markdown";
import { rendererVersion } from "./index";
import { escapeHtml, themedDocument } from "./document";
import { learningResourceJsonLd, type LearningResourceMeta } from "./learning-resource";
import type { SiteFile } from "./site";
import type { RenderTheme } from "./theme-css";

export interface CourseChapter {
  /** URL-safe slug. */
  slug: string;
  title: string;
  /** Root-relative href of this chapter's self-contained reading page
   *  (e.g. "chapters/<slug>.md.html"); the caller generates the file. */
  viewHref: string;
  /** Optional per-chapter slide deck / practice questions / print view
   *  (self-contained files) — each chapter authors these independently, so a
   *  chapter with no deck/questions yet simply omits that link. */
  slidesHref?: string;
  practiceHref?: string;
  pagedHref?: string;
}

export interface CourseSiteInput {
  title: string;
  /** Short course intro shown on the home page (markdown). */
  description?: string;
  /** Course-identity line under the title — instructor / course number /
   *  department, each optional; present fields join with " · ", the line is
   *  omitted entirely when none are set. */
  instructor?: string;
  courseNumber?: string;
  department?: string;
  chapters: CourseChapter[];
  /** ISO timestamp, passed in for deterministic builds. */
  builtAt: string;
  /** LRMI/schema.org metadata; when present, emitted as JSON-LD on the index (M30). */
  meta?: LearningResourceMeta;
  /** Render theme — matches the educator's editor selection (default dark). */
  theme?: RenderTheme;
}

/**
 * Home chrome, layered on top of the chosen orz theme (dark-elegant /
 * light-academic — see theme-css.ts). Structure and spacing are shared; the
 * one accent color is resolved per theme so it matches that theme's own link
 * color exactly (the two themes name their CSS custom properties differently,
 * so a literal is more robust here than trying to share one var name across
 * both) — everything else stays opacity-based grey, same principle the
 * original home chrome used, so it never clashes with either theme.
 */
function siteStyle(theme: RenderTheme = "dark"): string {
  const accent = theme === "light" ? "#1a1add" : "#5f8cff";
  return `<style>
:root{--home-accent:${accent}}
.course-hero{margin-bottom:clamp(2rem,5vw,3.5rem)}
/* dark-elegant's h1 is uppercase + letter-spaced for prose section headers —
   a long course title (one long word, or a title that just doesn't wrap
   favorably) can overflow its card at narrow widths without this. */
.course-hero h1{overflow-wrap:break-word;word-break:break-word;hyphens:auto}
@media (max-width:480px){
  .course-hero h1{font-size:1.5rem;letter-spacing:.02em;padding-left:.3em;padding-right:.3em}
}
.course-meta{margin:.4rem 0 0;font-size:.95rem;opacity:.7;letter-spacing:.01em;text-align:left;hyphens:none}
.course-meta .sep{margin:0 .55em;opacity:.5}
.course-intro{margin-top:1.35rem;opacity:.92}

.modules{margin:clamp(2.5rem,6vw,4rem) 0;text-align:left}
.modules-head{display:flex;align-items:baseline;justify-content:space-between;gap:1rem .75rem;flex-wrap:wrap}
.modules-count{font-size:.8rem;opacity:.55;white-space:nowrap}
.module-list{list-style:none;padding:0;margin:1.1rem 0 0}
.module-row{display:flex;gap:clamp(1rem,3vw,1.75rem);align-items:baseline;padding:1.15rem 0;border-bottom:1px solid rgba(128,128,128,.22)}
.module-row:first-child{border-top:1px solid rgba(128,128,128,.22)}
.module-num{flex:0 0 auto;min-width:1.7em;font-variant-numeric:tabular-nums;font-size:.95rem;font-weight:600;color:var(--home-accent);opacity:.85}
.module-main{flex:1;min-width:0;display:flex;flex-wrap:wrap;align-items:baseline;justify-content:space-between;gap:.4rem 1.5rem}
a.module-title{font-weight:600;font-size:1.05rem;text-decoration:none}
.module-formats{display:flex;gap:1.1rem;flex-wrap:wrap;font-size:.82rem}
.module-formats a{text-decoration:none;opacity:.78}
.module-formats a:hover,a.module-title:hover{opacity:.8}
.modules-empty{opacity:.65;font-style:italic}

.current-term{margin:clamp(2.5rem,6vw,4rem) 0;padding:1.5rem 1.75rem;border:1px dashed rgba(128,128,128,.4);border-radius:.75rem;text-align:left}
.current-term h2{margin-top:0 !important}
.current-note{opacity:.68;margin:0}

.site-footer{margin-top:3rem;padding-top:1rem;border-top:1px solid rgba(128,128,128,.2);font-size:.8rem;opacity:.6;text-align:left}

@media (max-width:640px){
  .module-row{flex-direction:column;gap:.4rem}
  .module-num{min-width:0}
}
</style>`;
}

/** Combine the home style with any extra head HTML (e.g. JSON-LD). */
function head(theme: RenderTheme | undefined, extra?: string): string {
  const style = siteStyle(theme);
  return extra ? `${style}\n${extra}` : style;
}

/**
 * Build the course home + build metadata. The chapter/practice pages themselves
 * (self-contained `.md.html`) are added by the caller.
 */
export function buildCourseSite(input: CourseSiteInput): SiteFile[] {
  const files: SiteFile[] = [];
  const indexHead = head(input.theme, input.meta ? learningResourceJsonLd(input.meta) : undefined);

  const metaParts = [input.instructor, input.courseNumber, input.department]
    .filter((s): s is string => Boolean(s && s.trim()))
    .map((s) => escapeHtml(s));
  const metaLine = metaParts.length
    ? `\n<p class="course-meta">${metaParts.join('<span class="sep">·</span>')}</p>`
    : "";
  const intro = input.description
    ? `\n<div class="course-intro">${md.render(input.description)}</div>`
    : "";
  const hero = `<header class="course-hero">\n<h1>${escapeHtml(input.title)}</h1>${metaLine}${intro}\n</header>`;

  const rows = input.chapters
    .map((c, i) => {
      const formats = [
        c.slidesHref ? `<a href="${escapeHtml(c.slidesHref)}">Slides</a>` : "",
        c.practiceHref ? `<a href="${escapeHtml(c.practiceHref)}">Practice questions</a>` : "",
        c.pagedHref ? `<a href="${escapeHtml(c.pagedHref)}">Print</a>` : "",
      ].filter(Boolean);
      const num = String(i + 1).padStart(2, "0");
      return `<li class="module-row">
<span class="module-num" aria-hidden="true">${num}</span>
<div class="module-main">
<a class="module-title" href="${escapeHtml(c.viewHref)}">${escapeHtml(c.title)}</a>
<span class="module-formats">${formats.join("")}</span>
</div>
</li>`;
    })
    .join("\n");
  const modulesBody = input.chapters.length
    ? `<ol class="module-list">\n${rows}\n</ol>`
    : `<p class="modules-empty">No modules published yet.</p>`;
  const count = input.chapters.length;
  const modules = `<section class="modules" aria-labelledby="modules-heading">
<div class="modules-head">
<h2 id="modules-heading">Modules</h2>${
    count ? `\n<span class="modules-count">${count} module${count === 1 ? "" : "s"}</span>` : ""
  }
</div>
${modulesBody}
</section>`;

  // Placeholder — the "current term" collection (announcements, due dates,
  // in-progress materials) isn't finalized yet; this just names the spot.
  const currentTerm = `<section class="current-term">
<h2>This term</h2>
<p class="current-note">Announcements and current-term materials will appear here once available.</p>
</section>`;

  const body = `${hero}\n${modules}\n${currentTerm}\n<footer class="site-footer">Published with Alembic</footer>`;

  files.push({
    path: "index.html",
    content: themedDocument({ title: input.title, bodyHtml: body, headHtml: indexHead, theme: input.theme }),
  });

  files.push({
    path: "build-info.json",
    content:
      JSON.stringify(
        { generator: "Alembic", renderer: rendererVersion(), builtAt: input.builtAt },
        null,
        2,
      ) + "\n",
  });
  // Tell GitHub Pages to serve files as-is (no Jekyll processing).
  files.push({ path: ".nojekyll", content: "" });

  return files;
}
